solution_code:
#include <iostream>

int stepped_calc(int a, int b) {
    int product = a * b;
    std::cerr << "[step] product=" << product << "\n";
    int diff = a - b;
    std::cerr << "[step] diff=" << diff << "\n";
    return product + diff;
}

int main() {
    int a, b;
    std::cin >> a >> b;
    std::cout << stepped_calc(a, b) << "\n";
    return 0;
}
